// ═══════════════════════════════════════════
// CONFIGURATION — Edit these values only
// ═══════════════════════════════════════════
const ODOO_URL = 'http://192.168.0.237:8069';
const ODOO_DB = 'aiqso_db';
const ODOO_USERNAME = 'quinn@aiqso.io';
const ODOO_API_KEY = 'REPLACE_WITH_YOUR_ODOO_API_KEY';
const ZAMMAD_URL = 'https://helpdesk.aiqso.io';
const ZAMMAD_API_TOKEN = 'REPLACE_WITH_YOUR_ZAMMAD_API_TOKEN';
// ═══════════════════════════════════════════

return [{
  json: {
    odoo_url: ODOO_URL,
    odoo_db: ODOO_DB,
    odoo_username: ODOO_USERNAME,
    odoo_api_key: ODOO_API_KEY,
    zammad_url: ZAMMAD_URL,
    zammad_token: ZAMMAD_API_TOKEN
  }
}];

// Split won leads into individual items for processing
const leads = $input.first().json.result || [];
const config = $('Config').item.json;
return leads
  .filter(lead => lead.email_from)
  .map(lead => ({
    json: {
      zammad_url: config.zammad_url,
      zammad_token: config.zammad_token,
      odoo_lead_name: lead.name,
      email: lead.email_from,
      firstname: (lead.contact_name || lead.partner_name || '').split(' ')[0] || '',
      lastname: (lead.contact_name || lead.partner_name || '').split(' ').slice(1).join(' ') || '',
      company: lead.partner_name || '',
      phone: lead.phone || ''
    }
  }));

